<div id="wf_container" class="wf-appcontainer wt-w-full wt-flex wt-flex-col-reverse md:wt-flex-row wf-items-stretch {customClasses}" style="max-height: {maxHeight}vh;">
    {#if menu}
    <div class="wf-menu sm:wt-w-full wt-mb-4 wt-basis-1/3 wt-grow-0 wt-flex wt-flex-col">
        <div class="sm:wt-visible">
            <label for="poi-search" id="wf-search-label" class="wt-hidden sm:wt-block" data-translation-element="web-search-label">Otsi kaupluse või brändi järgi</label>
            <div class="poi-search-container">
                <input class="wt-w-full" id="poi-search"  bind:value={search.keyword} on:change={ searchPOI } on:input={searchPOI} placeholder="" data-translation-attributes="placeholder" data-translation-attribute-placeholder="web-search-placeholder"/>
                {#if !searchVisible}
                <svg id="wf-search-icon" width="100" height="100" viewbox="0 0 24 24">
                    <path d="M11.1667 17.8333C14.8486 17.8333 17.8333 14.8486 17.8333 11.1667C17.8333 7.48477 14.8486 4.5 11.1667 4.5C7.48477 4.5 4.5 7.48477 4.5 11.1667C4.5 14.8486 7.48477 17.8333 11.1667 17.8333Z" fill="none" stroke="#6A747B" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                    <path d="M19.5 19.5L15.875 15.875" stroke="#6A747B" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                </svg>
                {/if}
                {#if searchVisible}
                <svg class="wf-icon search-clear" viewBox="0 0 16 19" on:click={clearSearch}>
                    <path d="m 0,14.5449 h 20.569799 v 2.05698 H 0 Z" transform="rotate(-45 0 14.5449)" />
                    <path transform="rotate(-135 14.5454 16)" d="m 14.5454,16 h 20.569799 v 2.05698 H 14.5454 Z" />
                </svg>
                {/if}
            </div>
            <div class="wf-groups-button">
                <button class="wp-element-button" on:click={showMenu}>
                    <span data-translation-element="web-categories">Categories</span>
                    <svg class="wf-icon" viewBox="0 0 14 8" on:click={hideMenu}>
                        <path d="M1 1L7 7L13 1" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
                    </svg>
                </button>
            </div>
        </div>
        <div id="wf-menu-content" class="wf-groups wt-overflow-hidden md:wt-overflow-y-auto wt-grow {groupsVisible ? 'wf-active' : ''}">
            <div id="wf-search-items-container">
                <div class="wf-menu-header hidden"on:click={clearSearch}>
                    <span data-translation-element="web-search-header">Otsi kauplust</span>
                    <svg class="wf-icon" viewBox="0 0 16 19">
                        <use xlink:href="#icon-clear" />
                    </svg>
                </div>
                <ul id="wf-search-items" class="wf-accordion"></ul>
            </div>
            <div id="wf-menu-items-container">
                <div class="wf-menu-header wf-mobile-menu-header wt-flex wt-items-center wt-justify-between sm:wt-hidden" on:click={hideMenu}>
                    <span data-translation-element="web-category-header">Sorteeri kategooria järgi</span>
                    <svg class="wf-icon" viewBox="0 0 16 19">
                        <use xlink:href="#icon-clear" />
                    </svg>
                </div>
                {#if !searchVisible}
                    <Menu groups={groups} on:poiclicked={openPOI} ></Menu>
                {/if}
                {#if searchVisible}
                <SearchResults results={search.results} on:poiclicked={openPOI} ></SearchResults>
                {/if}
            </div>
        </div>
        <!-- POI info -->
         {#if !enablePopup}
        <div class="wt-absolute wt-top-0 wt-left-0 wt-w-full wt-h-full">
            POI
        </div>
        {/if}
    </div>
    {/if}
    <div class="wf-map-container wt-grow">
        <div class="wf-map wt-w-full wt-relative sm:wt-flex">
            <div class="map-wrapper wt-w-full wt-h-full">
                <canvas id="map" width="400" height="300"></canvas>
            </div>
            <div class="wf-map-buttons wt-flex wt-flex-col wt-gap-12 {align == 'left' ? 'wt-left-0 md:wt-left-4' : 'wt-right-0 md:wt-right-4'}">
                <div id="wf-floors" class="wt-overflow-y-auto">
                {#each floors as [id, floor]}
                    <button class="wp-element-button {id == activeFloor ? 'wf-active' : ''}" on:click={showFloor(id)}>{floor}</button>
                {/each}
                </div>
                <div id="wf-additional-buttons">
                     
                    {#if enableCompass}
                    <button id="wf-compass-button" class="wp-element-button {compassRotating ? 'wf-active' : ''} " on:click={toggleCompass} title="Enable location">
                        <svg class="wf-icon wt-h-12" viewBox="0 0 16 19">
                            <use xlink:href="#icon-compass" />
                        </svg>
                    </button>
                    {/if}

                    {#if enableLocate}
                    <button id="wf-locate-button" class="wp-element-button {locateEnabled ? 'wf-active' : ''} " on:click={locateUser} title="Enable location">
                        {#if locateEnabled}
                            <svg class="wf-icon wt-h-12" viewBox="0 0 16 19">
                                <use xlink:href="#icon-explore" />
                            </svg>
                        {:else}
                            <svg class="wf-icon wt-h-12" viewBox="0 0 16 19">
                                <use xlink:href="#icon-navigate" />
                            </svg>
                        {/if}
                    </button>
                    {/if}
                </div>
            </div>
            {#if showPathText && pathTextEnabled}
                <div class="wf-path-text wt-absolute wt-top-4 wt-left-1/2 wt-ml-[-25%] wt-py-4 wt-px-8">{pathText}</div>
            {/if}
            {#if enablePopup}
            <div id="poi-popup">
                {#if popupPOI && popupVisible}
                <div class="poi-popup-content" >
                <span class="title">{popupPOI.getName(language)}</span>
                {#if popupPOI.web}
